property.content:
{{velocity}}
= $services.localization.render('sopManager.name') =
#set ($currentUser = $doc.fullName)
#set ($properties = 'doc.title,status,revisionOwner,revisedBy,approvedBy,revisionPlannedDate,pDFSecondaryTargetLocation,tags')
#set ($sourceParameters = 'className=SOPManager.Code.ControlledDocumentClass&translationPrefix=platform.index.&queryFilters=currentlanguage')
#set ($ownDocs = $services.query.xwql(
  'from doc.object(SOPManager.Code.ControlledDocumentClass) obj where obj.revisionOwner = :currentUser'
).bindValue('currentUser', $currentUser).setLimit(1).execute())
#set ($reviewDocs = $services.query.xwql(
  'from doc.object(SOPManager.Code.ControlledDocumentClass) obj where obj.revisedBy = :currentUser'
).bindValue('currentUser', $currentUser).setLimit(1).execute())
#set ($approveDocs = $services.query.xwql(
  'from doc.object(SOPManager.Code.ControlledDocumentClass) obj where obj.approvedBy = :currentUser'
).bindValue('currentUser', $currentUser).setLimit(1).execute())
#if ($ownDocs.size() > 0 || $reviewDocs.size() > 0 || $approveDocs.size() > 0)
  #if ($ownDocs.size() > 0)
    == $services.localization.render('sopManager.userProfile.ownedPages') ==
    {{liveData
      id="ownerTable"
      properties="$properties"
      source="liveTable"
      sourceParameters="$sourceParameters"
      filters="revisionOwner=$currentUser"
      queryFilters="currentlanguage"
    }}
      {
        "meta": {
          "propertyDescriptors": [
            {
              "id": "revisionOwner",
              "visible": false
            }
          ]
        }
      }
    {{/liveData}}
  #else
    {{info}}$services.localization.render('sopManager.userProfile.ownedPages.noResults'){{/info}}
  #end

  #if ($reviewDocs.size() > 0)
    == $services.localization.render('sopManager.userProfile.pagesToReview') ==
    {{liveData
      id="reviewerTable"
      properties="$properties"
      source="liveTable"
      sourceParameters="$sourceParameters"
      filters="revisedBy=$currentUser"
      queryFilters="currentlanguage"
    }}
      {
        "meta": {
          "propertyDescriptors": [
            {
              "id": "revisedBy",
              "visible": false
            }
          ]
        }
      }
    {{/liveData}}
  #else
    {{info}}$services.localization.render('sopManager.userProfile.pagesToReview.noResults'){{/info}}
  #end

  #if ($approveDocs.size() > 0)
    == $services.localization.render('sopManager.userProfile.pagesToApprove') ==
    {{liveData
      id="approvalTable"
      properties="$properties"
      source="liveTable"
      sourceParameters="$sourceParameters"
      filters="approvedBy=$currentUser"
      queryFilters="currentlanguage"
    }}
      {
        "meta": {
          "propertyDescriptors": [
            {
              "id": "approvedBy",
              "visible": false
            }
          ]
        }
      }
    {{/liveData}}
  #else
    {{info}}$services.localization.render('sopManager.userProfile.pagesToApprove.noResults'){{/info}}
  #end
#else
  {{info}}$services.localization.render('sopManager.userProfile.noResults'){{/info}}
#end
{{/velocity}}
